import React, { useState, useEffect, useCallback } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Header from './components/Header';
import LandingPage from './pages/LandingPage';
import Dashboard from './pages/Dashboard';
import AboutPage from './pages/AboutPage';
import api from './api/api';

const App = () => {
    // Global State for Authentication, User Details, and Profile Data
    const [user, setUser] = useState(null);
    const [profile, setProfile] = useState({});
    const [isLoading, setIsLoading] = useState(true);

    // --- 1. Fetch User Profile Data ---
    // This runs on load and after every successful profile update/login
    const fetchProfile = useCallback(async () => {
        const token = localStorage.getItem('token');
        if (!token) {
            setIsLoading(false);
            return;
        }

        try {
            // Note: The /api/profile endpoint returns the full user object including profile{}
            const response = await api.get('/profile'); 
            
            // The response.data contains { id, name, email, profile, token }
            const { profile: fetchedProfile, ...userDetails } = response.data;
            
            setUser(userDetails);
            setProfile(fetchedProfile || {}); // Ensure profile is not null

        } catch (error) {
            console.error('Error fetching user profile:', error);
            // If the token is invalid, log out
            handleLogout();
        } finally {
            setIsLoading(false);
        }
    }, []);

    // --- 2. Authentication Handlers ---
    
    const handleLogin = (userData) => {
        // userData contains { token, id, name, email, profile }
        localStorage.setItem('token', userData.token);
        
        const { profile: userProfile, ...userDetails } = userData;

        setUser(userDetails);
        setProfile(userProfile || {});
        
        // Navigate away from the auth page after successful login
        // Note: The Dashboard component will handle the final navigation/default view
    };

    const handleLogout = () => {
        localStorage.removeItem('token');
        setUser(null);
        setProfile({});
        // Use Navigate component for navigation outside of rendering cycle if needed, 
        // but often handled by the router/link click.
    };

    // --- 3. Initial Load Effect ---
    useEffect(() => {
        fetchProfile();
    }, [fetchProfile]);


    // --- 4. Loading State Rendering ---
    if (isLoading) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-[#0D1117] text-ai-green">
                <p className="text-xl">Loading application data...</p>
            </div>
        );
    }

    // --- 5. Main Application Structure and Routing ---
    return (
        <Router>
            <div className="App min-h-screen bg-[#0D1117]">
                <Header user={user} onLogout={handleLogout} />
                <Routes>
                    {/* Landing Page Route */}
                    <Route 
                        path="/" 
                        element={user ? <Navigate to="/dashboard" /> : <LandingPage onAuthSuccess={handleLogin} />} 
                    />
                    
                    {/* Authentication Routes (Register/Login handled internally by LandingPage/AuthForm) */}
                    <Route 
                        path="/auth/:type" 
                        element={user ? <Navigate to="/dashboard" /> : <LandingPage onAuthSuccess={handleLogin} />} 
                    />

                    {/* Dashboard/Protected Route */}
                    <Route 
                        path="/dashboard" 
                        element={
                            user ? (
                                <Dashboard 
                                    profile={profile} 
                                    setProfile={setProfile} 
                                    fetchProfile={fetchProfile} 
                                    user={user} // CRITICAL: Pass user for Dashboard Summary
                                />
                            ) : (
                                <Navigate to="/" replace />
                            )
                        } 
                    />

                    {/* About Page Route */}
                    <Route path="/about" element={<AboutPage />} />
                </Routes>
            </div>
        </Router>
    );
};

export default App;
